var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>방금 전 들어온 속보입니다.</color>","JPN":"<color=#ffd34c>先ほど入った速報です。</color>","ENG":"<color=#ffd34c>This just in.</color>","TWN":"<color=#ffd34c>剛剛收到一個速報。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>번화가인 B-10 구역 인근에서 총격전이 발생했다는 신고를 받고 출동했던 도시 경비대 대다수가 실신한 채로 발견되었습니다.</color>","JPN":"<color=#ffd34c>繁華街のB-10区域近くで銃撃戦が発生したとの通報を受けて出動した都市警備隊の大多数が、気を失った状態で発見されました。</color>","ENG":"<color=#ffd34c>City Guard officers who responded to a report on an alleged firefight in sector B-10 downtown were found unconscious.</color>","TWN":"<color=#ffd34c>接到在繁華街B-10區附近發生槍戰的舉報後，隨即出動的城市守衛現大多數昏迷不醒。</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>한편 시내 곳곳에서 범죄 조직의 조직원들이 만신창이가 된 채 무더기로 발견되어, 도시관리국은 긴급 기자회견을......</color>","JPN":"<color=#ffd34c>一方、市内各所で複数の犯罪組織のメンバーが怪我を負った状態で複数発見され、都市管理局は緊急記者会見を……</color>","ENG":"<color=#ffd34c>Meanwhile, members of criminal organizations were also found severely injured across the city. In response, City Management held an emergency press conference...</color>","TWN":"<color=#ffd34c>另外，在市內各處發現了遍體鱗傷的犯罪組織成員，城市管理局緊急召開記者會……</color>"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"사장님, 그러고 보니 베로니카 양은 찾아 보셨어요?","JPN":"社長、そういえばベロニカさんは見つかりましたか？","ENG":"Boss, any luck finding Veronica?","TWN":"老闆，貝洛妮卡有消息了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음. 여기저기 돌아다녔는데 종적을 찾을 수가 없더군.","JPN":"いや。各地を探してみたが行方は分からなかった。","ENG":"Hmm. I've searched everywhere, but haven't found any leads.","TWN":"唔，我找了很多地方，但沒有發現她的蹤跡。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L8_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"역시 모네 양 때문일까요? 두 사람 다 무사하면 좋을 텐데......","JPN":"やはりモネさんを探しているのでしょうか。二人とも無事であればいいのですが……","ENG":"Do you think she's still looking for Mone? I hope they're both okay...","TWN":"難道真的是因為莫妮嗎？希望兩個人都能平安無事……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L9_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"후우...... 어쩜 좋아......","JPN":"ふう……どうしよう……","ENG":"Oh dear... What should we do...","TWN":"哎……這可怎麼辦……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"저는 밀린 업무 처리하고 있을게요. 무슨 연락 있으면 저한테도 말씀해 주세요.","JPN":"それでは溜まった業務を処理しに戻ります。何か連絡がありましたら私にもお知らせください。","ENG":"I'll go catch up on some of paperwork. Please let me know if anything comes up.","TWN":"我先去工作了，如果有什麼消息別忘了也告訴我一聲。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"분위기가 어수선한 것 같으니까, 사장님도 외출은 조심하시고요.","JPN":"都心もあんな様子ですし、社長もお出かけはお控えくださいね。","ENG":"It seems like things are rough out there today. Please be careful if you go out.","TWN":"外面很亂，老闆你出去的時候務必要小心。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"부르셨나요, 사장님?","JPN":"お呼びですか、社長。","ENG":"Did you call me, Boss?","TWN":"老闆，您找我？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"도착했군, 샤오린 양. 혹시 오늘 뉴스는 봤나?","JPN":"来てくれたか、シャオリン。今日のニュースは見たかね？","ENG":"Ah, you're here, Xiao Lin. Have you seen the news today?","TWN":"你來了，曉琳。你看今天的新聞了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"네. 저격수에게 정보는 중요하니까요.","JPN":"はい、スナイパーにとって情報は大事ですから。","ENG":"Yes. Information is critical for snipers.","TWN":"當然了，對於狙擊手來說情報是非常重要的。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"도시 경비대가 배치한 블랙타이드 대원들이 메이드 복장의 여성과 치열한 교전을 벌였다고 나오더군요.","JPN":"都市警備隊が配置したブラックタイド隊員とメイド服の女性の間で激しい交戦があったようですね。","ENG":"They say the Black Tide operatives deployed by the City Guard had a fierce engagement with a woman in a maid outfit.","TWN":"聽說城市守衛部署的黑潮隊員和穿著女僕裝的女性進行了激烈交戰。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"블랙 네트워크에도 비슷한 목격담이 잔뜩 올라오고 있어요.","JPN":"ブラックネットワークにも似たような目撃談が次々と上がっています。","ENG":"The Dark Network is also full of similar accounts of the sighting.","TWN":"黑色網路上也出現了很多相關消息，描述的差不多。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"진위가 불확실하긴 하지만 결국 메이드 차림의 여성이 포위를 뚫고 사라졌다고......","JPN":"真偽は不明ですが、結果はメイド服の女性が包囲網を破って消えたと……","ENG":"Although they vary in terms of plausibility, they all basically say that a woman in a maid outfit broke through the guards' siege and vanished...","TWN":"雖然不知道是不是真的，但他們說最後穿著女僕裝的女性突出重圍消失了……"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그건 아마 베로니카 양인 것 같군. 모네를 납치한 사람들을 쫓고 있는 거겠지.","JPN":"それはおそらくベロニカだろうな。モネを攫った人物を追っているんだろう。","ENG":"That sounds like Veronica. She must be after whoever kidnapped Mone.","TWN":"應該是貝洛妮卡，她可能是在找綁架莫妮的人。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"제가 알기로는 오늘 자정을 기점으로 계약도 끝난다고 들었습니다만.","JPN":"私が知る限りでは本日の午前0時で契約が終了すると聞いていますが。","ENG":"I heard our contract with them ends at midnight today.","TWN":"不過，今天午夜一過，合同不就到期了嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아직도 꽤 신경을 쓰고 계신가 보군요.","JPN":"かなり気になさっているようですね。","ENG":"She must still be on your mind.","TWN":"看來您很擔心她啊。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"물론이지. 자정이 되려면 아직 시간이 남지 않았나.","JPN":"もちろんさ。午前0時までまだ時間が残っているじゃないか。","ENG":"Of course. We still got plenty of time till midnight.","TWN":"當然，現在離午夜還有一段時間不是嗎。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그 전까지 두 사람의 신변은 엄연히 우리 회사 소관일세.","JPN":"それまではあの二人の安否は我が社の責任さ。","ENG":"Until then, our company is responsible for their safety.","TWN":"在那之前，她們兩個人仍然是我們公司的員工。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"......그래서, 저에게 시키실 일이라도 있으신가요?","JPN":"……それで、私にするべき仕事があるのでしょうか？","ENG":"So... did you have a task for me?","TWN":"……所以，您有什麼事需要我做嗎？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"마음 같아서는 내가 직접 가고 싶지만 현실적으로는 어려운 일이지.","JPN":"私が直接探しにいきたい気持ちもあるが、現実的には難しくてね。","ENG":"I'd go out there myself, but it's not realistically feasible.","TWN":"我倒是很想親自出馬，不過太不切實際。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그러니 자네에게 은밀한 부탁을 하나 하려고 하네.","JPN":"だから君にこっそり頼みたい仕事があるんだ。","ENG":"So I wanted to ask you for a covert favor.","TWN":"所以我想讓你幫我辦一件隱秘的事。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"이번 일에는 샤오린 양이 제격인 것 같거든.","JPN":"今回の仕事にはシャオリン、君が一番相応しいと思っている。","ENG":"I thought you'd be perfect for this.","TWN":"這個事由曉琳你來辦最合適不過了。"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"은밀한...... 부탁이요?","JPN":"こっそり……ですか？","ENG":"A covert... favor?","TWN":"隱秘的……事？"},"stage":{"bg":"OFFICE","bgm":"THEMA_FLORA_MAID_SERVICE_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};